import{_ as p,o as t,c as e,a as _}from"./app.7f9bd173.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"article/2020.11.11.md"}'),a={name:"article/2020.11.11.md"},o=_("<h1>青春 初恋 眼泪</h1><p>作者: 孙飞</p><p>日期: 2020.11.21 3.05时分</p><hr><p> 今天是2020.11.11号 ✍🏻与凌晨3.05 <p>上一年差不多的时间 因为抑郁情绪爆发 导致跳楼极端行为的发生 告别了学校生活</p><p>经过一段时间的沉默 我决定重新开始 告别之前的自己 步入社会 打工挣钱</p><p>第一份工作 是在家附近 跟着远方亲戚家的表哥在鞋厂 去了当天就回来了心理是一方面 更多的是那里的工作 踩着机器给鞋子打孔 晚上喝着不热不冷的汤 回到宿舍 是令人感到压抑的三寸空间 晚上冷风吹进来 更多的是人间疾苦 于是当晚我哥就开车把我送回了家</p><p>我躺在床上 不断地肯定自己是个废物 一事无成的废物 自己为什么那么懦弱无能 眼泪再次无能地流了出来 或许只有自残能让自己舒服些吧 自残时流的眼泪全是对自己无能的谴责 像是一种赎罪</p><p>后来又一次找了新工作 跟着表姐在一家酒店上班 正好那家酒店 离我大爷家很近 下班后就回我大爷家住 在当服务员那段时间 还不错 病情明显减轻了 因为和我一起工作的都是大姨们 她们都很照顾我 病情复发也有 只不过已经过去一年了 很多细节我大抵都记得不怎么清晰了</p><p>貌似在除夕夜那天 我负责一个大房间的客人们 因为客人的身份特殊 领班特别嘱咐我一定要服务到位 记得我中途进去了准备换茶水 也记不清是为什么了 书记骂了我一句脏话 后来听同房客人说书记喝多了 爱说脏话 叫我别记心上</p><p>的确当时 我并没有太多纠结于此事 再往后大概7.8点左右 客人的孩子吃饱了 在大厅上跑着玩 大厅经理说让我看着孩子 别让他们上台阶去摸大屏幕 我当时也点头了 可是 我心并没有在哪里 我在想其他事 至于什么事 我也记不清了 结果 小孩子们跑到了台阶上 经理把我数落了一顿</p><p>我当时就想同一个世界下 房屋内是除夕家人统聚的欢声笑语 房屋外是沉默寡言 面无表情的我 于是我再次陷入消极的情绪 想起了家 想起了妈妈 眼泪再次流了出来</p><p>于是 我赶紧跑到洗手间 不想让别人看到我这狼狈的一幕 到了晚上客人基本都走了差不多了 我们快下班的时候 准备了聚餐 这原本也是我期待已久的</p><p>可真正到的时候 我并不是开心的 看向大家满脸笑容 虽身处热闹人群 可内心孤独无人知 终于就在所有人都在场的时刻 我爆发了 像是命运早已被安排好了一样 我把手机往地上一摔 大哭着 哽咽着 跑了出去 躺在地上 一遍又一遍地反问着自己 为什么 为什么 为什么始终总是败给自己的情绪 好在我姐姐安慰着 我隐隐地看见她也掉下了眼泪</p><p>我说 我再也没脸面回去工作了 就因为刚刚那一幕 别人怎么看我 我姐说到 大家都知道了 没事的 没事的 没事的 就这样我回去喝了一瓶啤酒 然后提前回家了 坐在小区楼下的板凳上 看向天空 眼泪又一次流了下来 这段算是在当服务员病情复发 印象最深的一段了 当然期间也有不少 只不过 怎么回忆也记不清了</p></p>",5),r=[o];function c(s,n,i,d,l,h){return t(),e("div",null,r)}const T=p(a,[["render",c]]);export{f as __pageData,T as default};
